#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int start;
    int end;
} Interval;

int compareIntervals(const void *a, const void *b) {
    const Interval *i1 = (const Interval *)a;
    const Interval *i2 = (const Interval *)b;
    return (i1->end > i2->end) - (i1->end < i2->end);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        Interval *arr = (Interval *)malloc(N * sizeof(Interval));
        for (int i = 0; i < N; ++i) {
            scanf("%d %d", &arr[i].start, &arr[i].end);
        }
        qsort(arr, N, sizeof(Interval), compareIntervals);
        int points = 0;
        int last = -1; // no point chosen yet
        for (int i = 0; i < N; ++i) {
            if (points == 0 || arr[i].start > last) {
                ++points;
                last = arr[i].end;
            }
        }
        printf("%d\n", points);
        free(arr);
    }
    return 0;
}

