import sys

def solve_one(it):
    n = int(next(it))
    intervals = []
    for _ in range(n):
        a = int(next(it))
        b = int(next(it))
        intervals.append((a, b))
    intervals.sort(key=lambda x: x[1])
    points = 0
    last = -1
    for a, b in intervals:
        if points == 0 or a > last:
            points += 1
            last = b
    return str(points)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out = []
    for _ in range(t):
        out.append(solve_one(it))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

